<div class="min-h-screen bg-slate-100 p-6 font-sans text-slate-800" id="rolesApp">
  <div class="grid grid-cols-12 gap-4">

    <!-- Sidebar: Roles -->
    <aside class="col-span-3 bg-white rounded-xl border border-slate-200 overflow-hidden flex flex-col" style="max-height: 520px;">
      <div class="p-4 border-b border-slate-200 flex items-center justify-between">
        <h3 class="font-semibold text-slate-900">Roles</h3>
        <button id="btnNewRole" class="w-7 h-7 rounded-lg border border-slate-200 hover:bg-slate-50 flex items-center justify-center text-slate-600 transition">
          <i data-lucide="plus" class="w-4 h-4"></i>
        </button>
      </div>
      <div class="p-3 border-b border-slate-200">
        <div class="relative">
          <i data-lucide="search" class="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"></i>
          <input id="roleSearch" type="text" placeholder="Buscar rol..." class="w-full pl-9 pr-3 py-2 text-sm bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-slate-900/10 focus:border-slate-300">
        </div>
      </div>
      <ul id="roleList" class="flex-1 overflow-y-auto p-2 space-y-1"></ul>
    </aside>

    <!-- Centro: Módulos -->
    <section class="col-span-5 bg-white rounded-xl border border-slate-200 flex flex-col" style="max-height: 520px;">
      <div class="p-4 border-b border-slate-200">
        <h3 class="font-semibold text-slate-900">Módulos</h3>
        <p class="text-xs text-slate-500 mt-0.5">Selecciona uno para configurar</p>
      </div>
      <div id="moduleList" class="flex-1 overflow-y-auto p-3 space-y-1"></div>
    </section>

    <!-- Derecha: Permisos -->
    <section class="col-span-4 bg-white rounded-xl border border-slate-200 flex flex-col" style="max-height: 520px;">
      <div class="p-4 border-b border-slate-200 flex items-center justify-between">
        <h3 class="font-semibold text-slate-900">Permisos del submódulo</h3>
        <div class="flex gap-2">
          <button id="btnEnableAll" class="text-xs px-3 py-1.5 rounded-lg border border-slate-200 hover:bg-slate-50 transition">Habilitar todas</button>
          <button id="btnDisableAll" class="text-xs px-3 py-1.5 rounded-lg border border-slate-200 hover:bg-slate-50 transition">Deshabilitar todas</button>
        </div>
      </div>
      <div id="permissionsPanel" class="flex-1 overflow-y-auto p-4 flex flex-col items-center justify-center text-slate-400">
        <i data-lucide="mouse-pointer-click" class="w-8 h-8 mb-2 text-slate-300"></i>
        <p class="text-sm">Submódulo no encontrado</p>
      </div>
    </section>
  </div>
</div>

<script>
(function() {
  const roles = [
    { id: 1, code: 'OP', name: 'Operador',        sections: '10/18', color: 'bg-slate-700',   desc: 'Acceso operativo al inventario y ventas', active: false, perms: { 'inv-entradas': 5, 'inv-salidas': 0, 'inv-traspasos': 0, 'inv-stock': 0 } },
    { id: 2, code: 'SU', name: 'Supervisor',      sections: '16/18', color: 'bg-rose-600',    desc: 'Supervisión de operaciones y reportes', active: true,  perms: { 'inv-entradas': 5, 'inv-salidas': 3, 'inv-traspasos': 5, 'inv-stock': 3 } },
    { id: 3, code: 'GE', name: 'Gerente',         sections: '18/18', color: 'bg-amber-500',   desc: 'Acceso total a gestión y reportes',     active: false, perms: { 'inv-entradas': 5, 'inv-salidas': 3, 'inv-traspasos': 5, 'inv-stock': 3 } },
    { id: 4, code: 'AD', name: 'Administrador',   sections: '22/22', color: 'bg-indigo-600',  desc: 'Control total del sistema',            active: false, perms: { 'inv-entradas': 5, 'inv-salidas': 3, 'inv-traspasos': 5, 'inv-stock': 3 } },
    { id: 5, code: 'AU', name: 'Auditor',         sections: '4/14',  color: 'bg-slate-500',   desc: 'Acceso de solo lectura para auditoría', active: false, perms: { 'inv-entradas': 1, 'inv-salidas': 1, 'inv-traspasos': 1, 'inv-stock': 1 } }
  ];

  const modules = [
    {
      id: 'inv', name: 'Inventario', icon: 'package', expanded: true,
      submodules: [
        { id: 'inv-entradas',  name: 'Entradas',  count: 5, icon: 'arrow-down-circle' },
        { id: 'inv-salidas',   name: 'Salidas',   count: 3, icon: 'arrow-up-circle'   },
        { id: 'inv-traspasos', name: 'Traspasos', count: 3, icon: 'arrow-left-right'  },
        { id: 'inv-stock',     name: 'Stock',     count: 3, icon: 'boxes'             }
      ]
    },
    {
      id: 'ven', name: 'Ventas', icon: 'shopping-cart', expanded: true,
      submodules: [
        { id: 'ven-pos',     name: 'Punto de venta', count: 5, icon: 'store'  },
        { id: 'ven-cotiz',   name: 'Cotizaciones',   count: 3, icon: 'file-text' },
        { id: 'ven-fact',    name: 'Facturación',    count: 4, icon: 'receipt' }
      ]
    }
  ];

  const permissionActions = ['Ver', 'Crear', 'Editar', 'Eliminar', 'Exportar'];

  let currentRoleId = 2;
  let currentSubId = null;
  let roleFilter = '';

  const $ = (s, p = document) => p.querySelector(s);
  const $$ = (s, p = document) => Array.from(p.querySelectorAll(s));

  function renderRoles() {
    const list = $('#roleList');
    list.innerHTML = '';
    roles
      .filter(r => r.name.toLowerCase().includes(roleFilter.toLowerCase()))
      .forEach(r => {
        const li = document.createElement('li');
        li.className = `group flex items-center gap-3 p-2.5 rounded-lg cursor-pointer transition ${r.id === currentRoleId ? 'bg-slate-50 ring-1 ring-slate-900' : 'hover:bg-slate-50'}`;
        li.dataset.id = r.id;
        li.innerHTML = `
          <div class="w-9 h-9 rounded-full ${r.color} text-white text-xs font-semibold flex items-center justify-center shrink-0">${r.code}</div>
          <div class="flex-1 min-w-0">
            <div class="flex items-center justify-between">
              <span class="font-medium text-sm ${r.id === currentRoleId ? 'text-slate-900' : 'text-slate-700'}">${r.name}</span>
              ${r.id === currentRoleId ? '<i data-lucide="check" class="w-4 h-4 text-slate-900"></i>' : ''}
            </div>
            <p class="text-xs text-slate-400 mt-0.5">${r.sections} sesiones</p>
          </div>
        `;
        li.addEventListener('click', () => {
          currentRoleId = r.id;
          renderRoles();
          renderHeader();
        });
        list.appendChild(li);
      });
    lucide.createIcons();
  }

  function renderHeader() {
    const r = roles.find(x => x.id === currentRoleId);
    if (!r) return;
    let header = $('#roleHeader');
    if (!header) {
      header = document.createElement('div');
      header.id = 'roleHeader';
      header.className = 'col-span-12 -mt-2 mb-2 flex items-center justify-between bg-white rounded-xl border border-slate-200 px-5 py-4';
      $('#rolesApp .grid').prepend(header);
    }
    header.innerHTML = `
      <div class="flex items-center gap-3">
        <div class="w-10 h-10 rounded-full ${r.color} text-white text-sm font-semibold flex items-center justify-center">${r.code}</div>
        <div>
          <div class="flex items-center gap-2">
            <h2 class="font-semibold text-slate-900">${r.name}</h2>
            <span class="text-xs px-2 py-0.5 rounded-full bg-emerald-50 text-emerald-700 border border-emerald-100 font-medium">${r.sections.split('/')[1] || ''} accesos</span>
          </div>
          <p class="text-xs text-slate-500 mt-0.5">${r.desc}</p>
        </div>
      </div>
      <div class="flex items-center gap-2">
        <button class="px-4 py-2 text-sm font-medium rounded-lg border border-slate-200 hover:bg-slate-50 transition">Editar</button>
        <button class="px-4 py-2 text-sm font-medium rounded-lg bg-slate-900 text-white hover:bg-slate-800 transition">Guardar</button>
      </div>
    `;
    lucide.createIcons();
  }

  function renderModules() {
    const list = $('#moduleList');
    list.innerHTML = '';
    modules.forEach(m => {
      const wrap = document.createElement('div');
      wrap.className = 'rounded-lg overflow-hidden border border-slate-100';
      wrap.innerHTML = `
        <button class="w-full flex items-center gap-2 px-3 py-2.5 bg-slate-50 hover:bg-slate-100 transition text-sm font-medium text-slate-700" data-toggle="${m.id}">
          <i data-lucide="${m.expanded ? 'chevron-down' : 'chevron-right'}" class="w-4 h-4 text-slate-500 transition-transform"></i>
          <i data-lucide="${m.icon}" class="w-4 h-4 text-emerald-600"></i>
          <span>${m.name}</span>
          <span class="ml-auto text-xs text-slate-400">${m.submodules.length}/${m.submodules.length}</span>
        </button>
        <div class="${m.expanded ? '' : 'hidden'} divide-y divide-slate-100" data-body="${m.id}">
          ${m.submodules.map(sm => {
            const role = roles.find(r => r.id === currentRoleId);
            const assigned = role?.perms?.[sm.id] ?? 0;
            return `
              <div class="submodule-item flex items-center gap-3 px-3 py-2.5 hover:bg-slate-50 cursor-pointer ${currentSubId === sm.id ? 'bg-slate-900 text-white hover:bg-slate-900' : ''}" data-sub="${sm.id}">
                <input type="checkbox" class="sub-chk w-4 h-4 rounded border-slate-300 text-slate-900 focus:ring-slate-900" ${assigned > 0 ? 'checked' : ''}>
                <i data-lucide="${sm.icon}" class="w-4 h-4 ${currentSubId === sm.id ? 'text-slate-300' : 'text-slate-400'}"></i>
                <span class="text-sm flex-1 ${currentSubId === sm.id ? 'text-white' : 'text-slate-700'}">${sm.name}</span>
                <span class="text-xs ${currentSubId === sm.id ? 'text-slate-300' : 'text-slate-400'}">${assigned}/${sm.count}</span>
              </div>
            `;
          }).join('')}
        </div>
      `;
      list.appendChild(wrap);
    });

    $$('[data-toggle]').forEach(btn => {
      btn.addEventListener('click', () => {
        const id = btn.dataset.toggle;
        const body = $(`[data-body="${id}"]`);
        const icon = btn.querySelector('[data-lucide="chevron-down"], [data-lucide="chevron-right"]');
        const expanded = !body.classList.contains('hidden');
        body.classList.toggle('hidden');
        icon.setAttribute('data-lucide', expanded ? 'chevron-right' : 'chevron-down');
        lucide.createIcons();
      });
    });

    $$('.submodule-item').forEach(item => {
      item.addEventListener('click', (e) => {
        if (e.target.classList.contains('sub-chk')) return;
        currentSubId = item.dataset.sub;
        renderModules();
        renderPermissions();
      });
      const chk = item.querySelector('.sub-chk');
      chk.addEventListener('change', () => {
        const role = roles.find(r => r.id === currentRoleId);
        const sm = modules.flatMap(m => m.submodules).find(s => s.id === item.dataset.sub);
        if (role && sm) {
          role.perms[sm.id] = chk.checked ? sm.count : 0;
          renderModules();
        }
      });
    });

    lucide.createIcons();
  }

  function renderPermissions() {
    const panel = $('#permissionsPanel');
    if (!currentSubId) {
      panel.innerHTML = `
        <i data-lucide="mouse-pointer-click" class="w-8 h-8 mb-2 text-slate-300"></i>
        <p class="text-sm">Submódulo no encontrado</p>
      `;
      lucide.createIcons();
      return;
    }
    const sm = modules.flatMap(m => m.submodules).find(s => s.id === currentSubId);
    const role = roles.find(r => r.id === currentRoleId);
    const assigned = role?.perms?.[sm.id] ?? 0;

    panel.innerHTML = `
      <div class="w-full">
        <div class="flex items-center gap-2 mb-4 pb-3 border-b border-slate-100">
          <i data-lucide="${sm.icon}" class="w-5 h-5 text-slate-700"></i>
          <h4 class="font-semibold text-slate-900">${sm.name}</h4>
          <span class="ml-auto text-xs px-2 py-0.5 rounded-full bg-slate-100 text-slate-600">${assigned}/${sm.count}</span>
        </div>
        <div class="space-y-2" id="permList"></div>
      </div>
    `;

    const permList = $('#permList');
    permissionActions.slice(0, sm.count).forEach((action, idx) => {
      const enabled = idx < assigned;
      const row = document.createElement('label');
      row.className = 'flex items-center justify-between p-3 rounded-lg border border-slate-100 hover:bg-slate-50 cursor-pointer transition';
      row.innerHTML = `
        <div class="flex items-center gap-2">
          <i data-lucide="${['eye','plus','edit','trash-2','download'][idx]}" class="w-4 h-4 text-slate-500"></i>
          <span class="text-sm text-slate-700">${action}</span>
        </div>
        <div class="relative">
          <input type="checkbox" class="perm-toggle sr-only peer" ${enabled ? 'checked' : ''}>
          <div class="w-9 h-5 bg-slate-200 peer-checked:bg-emerald-500 rounded-full transition relative">
            <div class="absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform peer-checked:translate-x-4"></div>
          </div>
        </div>
      `;
      permList.appendChild(row);
    });

    $$('.perm-toggle').forEach(t => {
      t.addEventListener('change', () => {
        const checked = $$('.perm-toggle').filter(x => x.checked).length;
        const role = roles.find(r => r.id === currentRoleId);
        if (role) role.perms[sm.id] = checked;
        renderModules();
        const badge = panel.querySelector('.rounded-full.bg-slate-100');
        if (badge) badge.textContent = `${checked}/${sm.count}`;
      });
    });

    lucide.createIcons();
  }

  $('#roleSearch').addEventListener('input', e => {
    roleFilter = e.target.value;
    renderRoles();
  });

  $('#btnEnableAll').addEventListener('click', () => {
    if (!currentSubId) return;
    const sm = modules.flatMap(m => m.submodules).find(s => s.id === currentSubId);
    const role = roles.find(r => r.id === currentRoleId);
    if (role && sm) {
      role.perms[sm.id] = sm.count;
      renderModules();
      renderPermissions();
    }
  });

  $('#btnDisableAll').addEventListener('click', () => {
    if (!currentSubId) return;
    const sm = modules.flatMap(m => m.submodules).find(s => s.id === currentSubId);
    const role = roles.find(r => r.id === currentRoleId);
    if (role && sm) {
      role.perms[sm.id] = 0;
      renderModules();
      renderPermissions();
    }
  });

  $('#btnNewRole').addEventListener('click', () => {
    const name = prompt('Nombre del nuevo rol:');
    if (!name) return;
    const code = name.slice(0, 2).toUpperCase();
    roles.push({
      id: Date.now(), code, name, sections: '0/18', color: 'bg-slate-500',
      desc: 'Rol personalizado', active: false, perms: {}
    });
    renderRoles();
  });

  renderHeader();
  renderRoles();
  renderModules();
  renderPermissions();
})();
</script>
